#include<bits/stdc++.h>
using namespace std;
int n,s[15],b[15];
int minans=1e9;
void dfs(int x,int y,int z){
    if(x>n){
        if(y==1&&z==0){
            return;
        }
        minans=min(minans,abs(y-z));
        return;
    }
    dfs(x+1,y*s[x],z+b[x]);
    dfs(x+1,y,z);
    return;
}
int main(){

    cin>>n;
    for(int i=1;i<=n;i++) cin>>s[i]>>b[i];
    dfs(1,1,0);
    cout<<minans;
    return 0;
}
